mapper.insert:
INSERT INTO friendship_rooms (
    name, description, theme_color, transport_type, cover_photo_url, cover_title
) VALUES (
    #{name}, #{description}, #{themeColor}, #{transportType}, #{coverPhotoUrl}, #{coverTitle}
)

mapper.update:
UPDATE friendship_rooms
name = #{request.name}, description = #{request.description}, theme_color = #{request.themeColor}, transport_type = #{request.transportType}, cover_photo_url = #{request.coverPhotoUrl}, cover_title = #{request.coverTitle},
WHERE id = #{roomId}

UPDATE friendship_rooms
SET status = 'INACTIVE', scheduled_delete_at = #{scheduledDeleteAt}
WHERE id = #{roomId}

UPDATE friendship_rooms
SET status = 'ACTIVE', scheduled_delete_at = NULL
WHERE id = #{roomId}

mapper.select:
SELECT COUNT(*)
FROM friendship_exp_logs
WHERE room_id = #{roomId}
  AND triggered_by = #{userId}
  AND action_type = 'MASCOT_INTERACT'
  AND created_at >= #{startOfDay}

mapper.update:
UPDATE friendship_rooms
SET friendship_level = #{friendshipLevel}, exp_point = #{expPoint}
WHERE id = #{roomId}

mapper.select:
SELECT COALESCE(SUM(exp_delta), 0)
FROM friendship_exp_logs
WHERE room_id = #{roomId}
  AND action_type = #{actionType}
  AND reference_id = #{referenceId}
